1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const CURSED_SURCHARGE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT_RATE = 0.2;
16	const LOYALTY_THRESHOLD = 2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
19	const PROCESSING_FEE = 5;
20	
21	interface Item {
22	  type: string;
23	  cursed?: boolean;
24	  enchantment?: number;
25	}
26	
27	function isComponent(type: string): boolean {
28	  return !(type in BASE_PREMIUMS);
29	}
30	
31	function mainItemPremium(items: Item[]): number {
32	  return items
33	    .filter((item) => !isComponent(item.type))
34	    .reduce((sum, item) => sum + itemBasePremium(item), 0);
35	}
36	
37	function componentCounts(items: Item[]): Map<string, number> {
38	  const counts = new Map<string, number>();
39	  for (const item of items) {
40	    if (isComponent(item.type)) {
41	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	    }
43	  }
44	  return counts;
45	}
46	
47	function componentPremium(items: Item[]): number {
48	  return [...componentCounts(items).values()].reduce(
49	    (total, count) => total + (count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM),
50	    0,
51	  );
52	}
53	
54	function itemBasePremium(item: Item): number {
55	  return BASE_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
56	}
57	
58	function singleItemSurcharge(item: Item): number {
59	  const base = itemBasePremium(item);
60	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
61	    + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
62	}
63	
64	function itemSurcharges(items: Item[]): number {
65	  return items.reduce((sum, item) => sum + singleItemSurcharge(item), 0);
66	}
67	
68	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
69	  const basePremium = mainItemPremium(items) + componentPremium(items);
70	  const surcharges = itemSurcharges(items);
71	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
72	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
73	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
74	  return Math.ceil(basePremium + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
75	}
76	
77	function validateItems(items: Item[]): void {
78	  for (const item of items) {
79	    if (!(item.type in BASE_PREMIUMS) && !KNOWN_COMPONENT_TYPES.has(item.type)) {
80	      throw new Error(`Unknown item type: ${item.type}`);
81	    }
82	  }
83	}
84	
85	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Item[] }> }) {
86	  const results = scenario.steps.map((step, index) => {
87	    validateItems(step.items ?? []);
88	    return { premium: computeQuotePremium(step.items ?? [], scenario.customer, index > 0) };
89	  });
90	  return { results };
91	}
